#include<bits/stdc++.h>
using namespace std;
int a[200005],n,x,y,f[200005],t;
int main()
{
	cin >> n;
	for(int i=1;i<=n;i++)
	{
		cin >> x;
		if(x==0)
		{
			cin >> y;
			t++;
			f[t]=max(f[t-1],y); 
		}
		else
			if(x==1 && t!=0)
			{
				t--;
			}
		else
			cout << f[t] << endl;
	}
	return 0;
}
